queries.sparql:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?service_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasServices ?child ; p:hasClinics ?parent . } GROUP BY ?child }
  ?child p:service_name ?service_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Clinics } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?service_name WHERE {
  ?clinics_services a :Clinics_Services .
  ?services a :Services .
  ?clinics_services p:hasServices ?services .
  ?clinics a :Clinics .
  ?clinics_services p:hasClinics ?clinics .
  ?clinics p:name ?name .
  ?services p:service_name ?service_name .
} }
  collective: { SELECT ?service_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasServices ?child ; p:hasClinics ?parent . } GROUP BY ?child }
  ?child p:service_name ?service_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Clinics } }
  FILTER(?nf = ?total)
} }
}
